import{_ as e,c as o,o as t,a8 as i}from"./chunks/framework.BrmF0WDH.js";const u=JSON.parse('{"title":"05-DataSource数据驱动","description":"","frontmatter":{},"headers":[],"relativePath":"onboarding/05-DataSource数据驱动/index.md","filePath":"onboarding/05-DataSource数据驱动/index.md","lastUpdated":1777649372000}'),l={name:"onboarding/05-DataSource数据驱动/index.md"};function d(c,a,r,n,s,p){return t(),o("div",null,a[0]||(a[0]=[i('<h1 id="_05-datasource数据驱动" tabindex="1">05-DataSource数据驱动 <a class="header-anchor" href="#_05-datasource数据驱动" aria-label="Permalink to &quot;05-DataSource数据驱动&quot;">​</a></h1><h2 id="数据源不是附属功能-而是第二条主链路" tabindex="1">数据源不是附属功能，而是第二条主链路 <a class="header-anchor" href="#数据源不是附属功能-而是第二条主链路" aria-label="Permalink to &quot;数据源不是附属功能，而是第二条主链路&quot;">​</a></h2><p>这个项目的第一条主链路是：</p><p><code>Schema -&gt; Core -&gt; Runtime -&gt; 页面</code></p><p>第二条主链路是：</p><p><code>DataSource -&gt; 依赖触发 -&gt; Node 重编译 -&gt; 页面局部更新</code></p><p>如果你只理解第一条，就只能做静态拖拽页面；理解第二条，才真正理解“低代码页面为什么是活的”。</p><h2 id="datasourcemanager-管什么" tabindex="1"><code>DataSourceManager</code> 管什么 <a class="header-anchor" href="#datasourcemanager-管什么" aria-label="Permalink to &quot;`DataSourceManager` 管什么&quot;">​</a></h2><p><code>packages/data-source/src/data-source-manager.ts</code> 负责：</p><ul><li>实例化所有数据源</li><li>注册数据源方法为全局事件</li><li>接收数据源 change 事件</li><li>维护依赖表 <code>dataSourceDep</code></li><li>在数据变化时触发受影响节点更新</li></ul><h2 id="依赖表长什么样" tabindex="1">依赖表长什么样 <a class="header-anchor" href="#依赖表长什么样" aria-label="Permalink to &quot;依赖表长什么样&quot;">​</a></h2><p>依赖表本质上是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Map&lt;</span></span>\n<span class="line"><span>  dataSourceId,</span></span>\n<span class="line"><span>  Map&lt;</span></span>\n<span class="line"><span>    fieldId,</span></span>\n<span class="line"><span>    Set&lt;depEffect&gt;</span></span>\n<span class="line"><span>  &gt;</span></span>\n<span class="line"><span>&gt;</span></span></code></pre></div><p>每个依赖记录至少包含：</p><ul><li>哪个节点 <code>field</code></li><li>依赖的是哪个属性路径 <code>key</code></li><li>原始表达式 <code>rawValue</code></li><li>是普通数据依赖还是条件依赖 <code>type</code></li></ul><h2 id="依赖是在哪收集的" tabindex="1">依赖是在哪收集的 <a class="header-anchor" href="#依赖是在哪收集的" aria-label="Permalink to &quot;依赖是在哪收集的&quot;">​</a></h2><p>不是在数据源里收集，而是在 <code>LowCodeNode</code> 编译节点时收集。</p><h3 id="普通数据依赖" tabindex="1">普通数据依赖 <a class="header-anchor" href="#普通数据依赖" aria-label="Permalink to &quot;普通数据依赖&quot;">​</a></h3><p><code>compileNode</code> 遇到 <code>${source.field}</code> 时：</p><ul><li>先调用 <code>track</code></li><li>再把表达式编译成当前值</li></ul><h3 id="条件依赖" tabindex="1">条件依赖 <a class="header-anchor" href="#条件依赖" aria-label="Permalink to &quot;条件依赖&quot;">​</a></h3><p><code>compileCond</code> 遍历 <code>ifShow</code> 数组时：</p><ul><li>找出条件引用的数据字段</li><li>以 <code>cond</code> 类型注册依赖</li></ul><p>这说明依赖收集发生在“节点解释阶段”，不是“数据变化阶段”。</p><h2 id="数据变化时具体发生了什么" tabindex="1">数据变化时具体发生了什么 <a class="header-anchor" href="#数据变化时具体发生了什么" aria-label="Permalink to &quot;数据变化时具体发生了什么&quot;">​</a></h2><p>以 <code>DataSource.setData</code> 为例：</p><ol><li>数据源内部更新 <code>data</code></li><li>发出 <code>change</code> 事件</li><li><code>createDataSourceManager</code> 监听到 change</li><li>调 <code>trigger(sourceId, fieldId)</code></li><li>找到所有受影响节点</li><li>对每个节点重新写回表达式或重新计算条件</li><li>调 <code>LowCodeNode.setData</code></li><li>runtime 页面配置被替换，Vue 重新渲染</li></ol><h2 id="为什么这里能做到-相对精确更新" tabindex="1">为什么这里能做到“相对精确更新” <a class="header-anchor" href="#为什么这里能做到-相对精确更新" aria-label="Permalink to &quot;为什么这里能做到“相对精确更新”&quot;">​</a></h2><p>因为依赖不是按页面整体重算，而是按：</p><ul><li>数据源 id</li><li>字段 id</li><li>节点 field</li></ul><p>三层信息做映射。</p><p>虽然现在实现还比较原始，但方向是正确的：它在试图从“整页重渲染”走向“按依赖定点更新”。</p><h2 id="数据源方法为什么能当事件调用" tabindex="1">数据源方法为什么能当事件调用 <a class="header-anchor" href="#数据源方法为什么能当事件调用" aria-label="Permalink to &quot;数据源方法为什么能当事件调用&quot;">​</a></h2><p>在 <code>DataSourceManager.init</code> 里，数据源里的方法会被注册成全局事件：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>${ds.id}:${method.name}</span></span></code></pre></div><p>这样组件事件、生命周期钩子、其他逻辑都可以通过 <code>app.emit(...)</code> 去调用数据源方法。</p><p>这让数据源不仅是“数据容器”，还是“可配置方法容器”。</p><h2 id="base-和-http-的差异" tabindex="1"><code>base</code> 和 <code>http</code> 的差异 <a class="header-anchor" href="#base-和-http-的差异" aria-label="Permalink to &quot;`base` 和 `http` 的差异&quot;">​</a></h2><h3 id="base" tabindex="1"><code>base</code> <a class="header-anchor" href="#base" aria-label="Permalink to &quot;`base`&quot;">​</a></h3><p>更像内存态状态容器：</p><ul><li>根据字段配置生成默认值</li><li>支持自定义方法</li><li>手动 <code>setData</code></li></ul><h3 id="http" tabindex="1"><code>http</code> <a class="header-anchor" href="#http" aria-label="Permalink to &quot;`http`&quot;">​</a></h3><p>在 <code>base</code> 之上再加：</p><ul><li>请求配置</li><li><code>beforeRequest / afterRequest</code></li><li><code>beforeInit / afterInit</code></li><li><code>autoFetch</code></li><li><code>responseOptions.dataPath</code></li></ul><p>所以 <code>http</code> 数据源本质是“带生命周期的请求型状态源”。</p><h2 id="当前实现里要知道的几个现实问题" tabindex="1">当前实现里要知道的几个现实问题 <a class="header-anchor" href="#当前实现里要知道的几个现实问题" aria-label="Permalink to &quot;当前实现里要知道的几个现实问题&quot;">​</a></h2><h3 id="_1-依赖触发仍偏工程化-离完整响应式还有距离" tabindex="1">1. 依赖触发仍偏工程化，离完整响应式还有距离 <a class="header-anchor" href="#_1-依赖触发仍偏工程化-离完整响应式还有距离" aria-label="Permalink to &quot;1. 依赖触发仍偏工程化，离完整响应式还有距离&quot;">​</a></h3><p>当前实现是手动 track / trigger，不是 Proxy 式自动依赖系统。</p><h3 id="_2-触发后会回写节点配置" tabindex="1">2. 触发后会回写节点配置 <a class="header-anchor" href="#_2-触发后会回写节点配置" aria-label="Permalink to &quot;2. 触发后会回写节点配置&quot;">​</a></h3><p>这意味着你调试数据问题时，不只是看数据源本身，还要看节点配置是否被重写。</p><h3 id="_3-部分代码里还有调试日志" tabindex="1">3. 部分代码里还有调试日志 <a class="header-anchor" href="#_3-部分代码里还有调试日志" aria-label="Permalink to &quot;3. 部分代码里还有调试日志&quot;">​</a></h3><p>例如 <code>track</code>、<code>trigger</code> 里直接 <code>console.log</code>，说明这一层仍处于比较原始的工程阶段。</p><h2 id="新人理解这一层最重要的一个公式" tabindex="1">新人理解这一层最重要的一个公式 <a class="header-anchor" href="#新人理解这一层最重要的一个公式" aria-label="Permalink to &quot;新人理解这一层最重要的一个公式&quot;">​</a></h2><p>不是：</p><p><code>数据源变化 -&gt; 组件直接更新</code></p><p>而是：</p><p><code>数据源变化 -&gt; 找到依赖节点 -&gt; 重编译节点配置 -&gt; 组件根据新配置渲染</code></p><p>只要记住这一点，很多“为什么组件没直接监听数据源”的疑问就会消失。</p>',58)]))}const b=e(l,[["render",d]]);export{u as __pageData,b as default};
